mapper.select:
select apt_cmplex_no
from mgmt_office
where mgmt_ofc_no = #{mgmtOfcNo}

select apt_cmplex_nm
from apt_complex
where apt_cmplex_no = #{aptCmplexNo}

select count(*)
from facility
where apt_cmplex_no = #{aptCmplexNo}
and facility_no = #{facilityNo}

mapper.insert:
insert into meter_upload_hstry (
meter_upload_hstry_no
, utility_provider_no
, apt_cmplex_no
, file_group_no
, upload_dt
, upload_user_no
, total_cnt
, upload_stts_cd
, err_cn
, rmrk_cn
) values (
#{meterUploadHstryNo}
, #{utilityProviderNo}
, #{aptCmplexNo}
, #{fileGroupNo}
, sysdate
, #{uploadUserNo}
, #{totalCnt}
, #{uploadSttsCd}
, #{errCn}
, #{rmrkCn}
)

insert into meter_hstry (
meter_hstry_no
, facility_no
, ho_no
, meter_scope
, meter_ty_cd
, meter_dt
, pre_val
, curr_val
, meter_cn
, meter_rslt_cd
, reg_dt
, utility_provider_no
) values (
'MH' || to_char(sysdate, 'yymmdd') || lpad(seq_meter_hstry.nextval, 7, '0')
, #{facilityNo}
, #{hoNo}
, #{meterScope}
, #{meterTyCd}
, #{meterDt}
, #{preVal}
, #{currVal}
, #{meterCn}
, #{meterRsltCd}
, sysdate
, #{utilityProviderNo}
)

mapper.update:
update meter_hstry
set meter_dt      = #{meterDt}
, pre_val       = #{preVal}
, curr_val      = #{currVal}
, meter_rslt_cd = #{meterRsltCd}
, meter_cn      = #{meterCn}
, mdf_dt        = sysdate
where meter_hstry_no = #{meterHstryNo}
